  ('aboriginal-f0899a01-moex-00057', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '環境部與某直轄市政府環境保護局，就垃圾掩埋場之再利用計畫訂定行政契約，並有自願接受強制執 行約定。此二機關就該約定應分別經由何者認可始生效力？', '["環境部部長；直轄市政府環境保護局局長", "行政院；直轄市市長", "內政部部長；直轄市市長", "環境部部長；內政部部長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
