  ('aboriginal-f0899a01-moex-00061', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依訴願法規定，有關訴願程序中支付金錢之敘述，下列何者正確？', '["提起訴願不必繳納訴願費用，但須預繳寄送書類之郵資", "訴願人申請鑑定，受理訴願機關認有必要而送鑑定，應由訴願人負擔鑑定費用", "訴願人得預納費用請求訴願卷宗之繕本、影本或節本", "訴願人須先提出相當金額之擔保，始得申請停止原處分之執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
